import React, { useState, useEffect, useRef, useCallback } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import { useSocket } from "../context/SocketContext";
import CallModal from "../components/CallModal";
import IncomingCallAlert from "../components/IncomingCallAlert";

// ── Helpers ──────────────────────────────────────────────────────────────────
const API = process.env.REACT_APP_SERVER_URL || "http://localhost:5000";

function formatTime(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function formatSize(bytes) {
  if (bytes < 1024) return bytes + " B";
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
  return (bytes / (1024 * 1024)).toFixed(1) + " MB";
}

// ── Sub-components ────────────────────────────────────────────────────────────

function MessageBubble({ msg, isSent }) {
  const fileUrl = msg.fileUrl ? `${API}${msg.fileUrl}` : null;

  if (msg.type === "image") {
    return (
      <div className="bg-surface-container-lowest p-2 rounded-2xl shadow-sm">
        <img
          src={fileUrl}
          alt={msg.fileName || "image"}
          className="rounded-xl max-w-[260px] max-h-[200px] object-cover cursor-pointer"
          onClick={() => window.open(fileUrl, "_blank")}
        />
      </div>
    );
  }
  if (msg.type === "audio" || msg.type === "ai_voice") {
    return (
      <div className={`p-3 rounded-2xl shadow-sm flex items-center gap-2 ${isSent ? "bg-primary-container" : "bg-surface-container-lowest"}`}>
        <span className={`material-symbols-outlined ${isSent ? "text-white" : "text-primary"}`}>graphic_eq</span>
        <audio controls src={fileUrl} className="max-w-[200px] h-8" />
        {msg.type === "ai_voice" && (
          <span className={`text-[10px] font-semibold ${isSent ? "text-white/60" : "text-primary/60"}`}>AI</span>
        )}
      </div>
    );
  }
  if (msg.type === "video") {
    return (
      <div className="bg-surface-container-lowest p-2 rounded-2xl shadow-sm">
        <video controls src={fileUrl} className="rounded-xl max-w-[260px] max-h-[200px]" />
      </div>
    );
  }
  if (msg.type === "file") {
    return (
      <div className={`p-3 rounded-2xl shadow-sm flex items-center gap-3 ${isSent ? "bg-primary-container" : "bg-surface-container-lowest"}`}>
        <div className={`w-9 h-9 rounded-xl flex items-center justify-center ${isSent ? "bg-white/20" : "bg-primary/10"}`}>
          <span className={`material-symbols-outlined text-sm ${isSent ? "text-white" : "text-primary"}`}>folder_zip</span>
        </div>
        <div>
          <p className={`text-xs font-semibold truncate max-w-[160px] ${isSent ? "text-white" : "text-on-surface"}`}>{msg.fileName}</p>
          <p className={`text-[10px] ${isSent ? "text-white/60" : "text-on-surface-variant"}`}>{formatSize(msg.fileSize)}</p>
        </div>
        <a href={fileUrl} download={msg.fileName} className={`ml-1 ${isSent ? "text-white/80 hover:text-white" : "text-primary hover:text-primary/80"}`}>
          <span className="material-symbols-outlined text-sm">download</span>
        </a>
      </div>
    );
  }
  // text
  return (
    <div className={`p-4 rounded-2xl text-sm shadow-sm ${isSent
      ? "bg-primary-container text-white sent-bubble shadow-[0px_8px_16px_rgba(108,92,231,0.15)]"
      : "bg-surface-container-lowest text-on-surface received-bubble"
    }`}>
      {msg.content}
    </div>
  );
}

function ConversationRow({ contact, unread, lastMsg, active, onClick, isOnline }) {
  const avatar = contact.avatar ? `${API}${contact.avatar}` : null;
  return (
    <div className="px-4 py-1">
      <div
        onClick={onClick}
        className={`flex items-center gap-3 p-3 rounded-2xl cursor-pointer transition-all duration-200 relative
          ${active ? "bg-surface-container-low" : "hover:bg-surface-container-low/50"}`}
      >
        {active && <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-primary rounded-r-full" />}
        <div className="relative">
          {avatar ? (
            <img src={avatar} alt={contact.username} className="w-12 h-12 rounded-2xl object-cover" />
          ) : (
            <div className="w-12 h-12 rounded-2xl bg-primary-container flex items-center justify-center">
              <span className="text-white font-bold text-lg">{contact.username[0].toUpperCase()}</span>
            </div>
          )}
          {isOnline && (
            <div className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-2 border-white rounded-full" />
          )}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-baseline mb-0.5">
            <span className="text-sm font-semibold text-on-surface truncate">{contact.username}</span>
            {lastMsg && <span className="text-[10px] text-on-surface-variant">{formatTime(lastMsg.createdAt)}</span>}
          </div>
          <div className="flex justify-between items-center">
            <p className={`text-xs truncate pr-2 ${unread > 0 ? "text-primary font-medium" : "text-on-surface-variant"}`}>
              {lastMsg
                ? lastMsg.type !== "text" ? `Sent a ${lastMsg.type}` : lastMsg.content
                : "Start a conversation"}
            </p>
            {unread > 0 && (
              <div className="w-4 h-4 bg-primary text-[10px] text-white flex items-center justify-center rounded-full shrink-0">
                {unread}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Main ChatPage ─────────────────────────────────────────────────────────────
export default function ChatPage() {
  const { user, logout } = useAuth();
  const { socket, isOnline, incomingCall, setIncomingCall } = useSocket();

  const [contacts, setContacts] = useState([]);
  const [search, setSearch] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [activeContact, setActiveContact] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [typing, setTyping] = useState(false);
  const [partnerTyping, setPartnerTyping] = useState(false);
  const [unreadMap, setUnreadMap] = useState({});
  const [lastMsgMap, setLastMsgMap] = useState({});
  const [activeTab, setActiveTab] = useState("chats"); // chats | contacts | calls | settings
  const [callData, setCallData] = useState(null); // active outgoing call
  const [incomingCallAnswered, setIncomingCallAnswered] = useState(null);
  const [recording, setRecording] = useState(false);
  const [mediaRecorder, setMediaRecorder] = useState(null);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);

  const bottomRef = useRef(null);
  const fileInputRef = useRef(null);
  const typingTimer = useRef(null);
  const audioChunks = useRef([]);

  // ── Load contacts / users ──────────────────────────────────────────────────
  useEffect(() => {
    axios.get("/api/users").then((r) => setContacts(r.data.users));
    axios.get("/api/messages/unread/count").then((r) => {
      const map = {};
      r.data.counts.forEach((c) => { map[c._id] = c.count; });
      setUnreadMap(map);
    });
  }, []);

  // ── Search users ───────────────────────────────────────────────────────────
  useEffect(() => {
    if (!search) { setSearchResults([]); return; }
    const t = setTimeout(() => {
      axios.get(`/api/users?search=${search}`).then((r) => setSearchResults(r.data.users));
    }, 300);
    return () => clearTimeout(t);
  }, [search]);

  // ── Load messages when contact changes ────────────────────────────────────
  useEffect(() => {
    if (!activeContact) return;
    axios.get(`/api/messages/${activeContact._id}`).then((r) => {
      setMessages(r.data.messages);
      setUnreadMap((prev) => ({ ...prev, [activeContact._id]: 0 }));
      socket?.emit("markRead", { senderId: activeContact._id });
    });
  }, [activeContact]);

  // ── Scroll to bottom ───────────────────────────────────────────────────────
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // ── Socket listeners ───────────────────────────────────────────────────────
  useEffect(() => {
    if (!socket) return;

    socket.on("receiveMessage", (msg) => {
      const senderId = msg.sender._id || msg.sender;
      if (activeContact && senderId === activeContact._id) {
        setMessages((prev) => [...prev, msg]);
        socket.emit("markRead", { senderId });
      } else {
        setUnreadMap((prev) => ({ ...prev, [senderId]: (prev[senderId] || 0) + 1 }));
      }
      setLastMsgMap((prev) => ({ ...prev, [senderId]: msg }));
    });

    socket.on("messageSent", (msg) => {
      setMessages((prev) => {
        const exists = prev.find((m) => m._id === msg._id);
        return exists ? prev : [...prev, msg];
      });
      const receiverId = msg.receiver._id || msg.receiver;
      setLastMsgMap((prev) => ({ ...prev, [receiverId]: msg }));
    });

    socket.on("userTyping", ({ userId, isTyping }) => {
      if (activeContact && userId === activeContact._id) setPartnerTyping(isTyping);
    });

    return () => {
      socket.off("receiveMessage");
      socket.off("messageSent");
      socket.off("userTyping");
    };
  }, [socket, activeContact]);

  // ── Typing indicator ───────────────────────────────────────────────────────
  const handleTextChange = (e) => {
    setText(e.target.value);
    if (!activeContact) return;
    if (!typing) {
      setTyping(true);
      socket?.emit("typing", { receiverId: activeContact._id, isTyping: true });
    }
    clearTimeout(typingTimer.current);
    typingTimer.current = setTimeout(() => {
      setTyping(false);
      socket?.emit("typing", { receiverId: activeContact._id, isTyping: false });
    }, 1500);
  };

  // ── Send text message ──────────────────────────────────────────────────────
  const sendMessage = useCallback(() => {
    if (!text.trim() || !activeContact) return;
    socket?.emit("sendMessage", { receiverId: activeContact._id, content: text, type: "text" });
    setText("");
    socket?.emit("typing", { receiverId: activeContact._id, isTyping: false });
  }, [text, activeContact, socket]);

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  // ── File upload ────────────────────────────────────────────────────────────
  const uploadFile = async (file) => {
    if (!activeContact || !file) return;
    const formData = new FormData();
    formData.append("file", file);
    formData.append("receiverId", activeContact._id);
    try {
      const res = await axios.post("/api/messages/upload", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      const msg = res.data.message;
      // Also emit via socket so receiver gets it live
      socket?.emit("sendMessage", {
        receiverId: activeContact._id,
        content: msg.content,
        type: msg.type,
        fileUrl: msg.fileUrl,
        fileName: msg.fileName,
        fileSize: msg.fileSize,
      });
    } catch (err) {
      alert("Upload failed: " + (err.response?.data?.message || err.message));
    }
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) uploadFile(file);
    e.target.value = "";
  };

  // ── AI Voice recording ─────────────────────────────────────────────────────
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      audioChunks.current = [];
      mr.ondataavailable = (e) => audioChunks.current.push(e.data);
      mr.onstop = async () => {
        const blob = new Blob(audioChunks.current, { type: "audio/webm" });
        const file = new File([blob], `voice-${Date.now()}.webm`, { type: "audio/webm" });
        stream.getTracks().forEach((t) => t.stop());
        // Upload as audio message
        await uploadFile(file);
      };
      mr.start();
      setMediaRecorder(mr);
      setRecording(true);
    } catch {
      alert("Microphone access denied");
    }
  };

  const stopRecording = () => {
    mediaRecorder?.stop();
    setRecording(false);
    setMediaRecorder(null);
  };

  // ── Video / Voice call ─────────────────────────────────────────────────────
  const startCall = (type) => {
    if (!activeContact) return;
    setCallData({ userId: activeContact._id, myId: user._id, callType: type, name: activeContact.username });
  };

  const handleAcceptCall = () => {
    setIncomingCallAnswered({ ...incomingCall });
    setIncomingCall(null);
  };

  const handleRejectCall = () => {
    socket?.emit("rejectCall", { to: incomingCall.from });
    setIncomingCall(null);
  };

  // ── Emoji picker (simple) ──────────────────────────────────────────────────
  const emojis = ["😀","😂","😍","🥰","😎","🤔","👍","❤️","🔥","✨","🎉","🙏","😭","🥺","💯","🎨"];
  const insertEmoji = (e) => {
    setText((prev) => prev + e);
    setShowEmojiPicker(false);
  };

  // ── Render ─────────────────────────────────────────────────────────────────
  const displayContacts = search ? searchResults : contacts;

  return (
    <div className="bg-background text-on-surface h-screen overflow-hidden flex">
      {/* ── Call Modals ─────────────────────────────────────────────────── */}
      {callData && (
        <CallModal
          callData={callData}
          onEnd={() => setCallData(null)}
          isIncoming={false}
        />
      )}
      {incomingCallAnswered && (
        <CallModal
          callData={incomingCallAnswered}
          onEnd={() => setIncomingCallAnswered(null)}
          isIncoming={true}
        />
      )}
      {incomingCall && !incomingCallAnswered && (
        <IncomingCallAlert
          callData={incomingCall}
          onAccept={handleAcceptCall}
          onReject={handleRejectCall}
        />
      )}

      {/* ── Side Nav (64px) ─────────────────────────────────────────────── */}
      <aside className="fixed left-0 top-0 h-full z-50 h-screen w-16 flex flex-col items-center py-6 bg-surface-container-lowest antialiased">
        <div className="mb-8">
          <span className="text-[#6C5CE7] font-bold text-2xl">M</span>
        </div>
        <nav className="flex flex-col gap-6 flex-1 items-center">
          {[
            { key: "chats", icon: "chat_bubble", label: "Chats" },
            { key: "contacts", icon: "group", label: "Contacts" },
            { key: "calls", icon: "call", label: "Calls" },
            { key: "stories", icon: "amp_stories", label: "Stories" },
            { key: "settings", icon: "settings", label: "Settings" },
          ].map((tab) => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              title={tab.label}
              className={`relative transition-transform scale-95 active:scale-90 ${
                activeTab === tab.key
                  ? "text-[#6C5CE7] before:content-[''] before:absolute before:-left-5 before:w-1 before:h-6 before:bg-[#6C5CE7] before:rounded-r-full"
                  : "text-slate-400 hover:text-[#6C5CE7] transition-all duration-200"
              }`}
            >
              <span className="material-symbols-outlined text-2xl">{tab.icon}</span>
            </button>
          ))}
        </nav>
        <div className="mt-auto flex flex-col items-center gap-6">
          <button onClick={logout} className="text-slate-400 hover:text-red-400 transition-colors" title="Logout">
            <span className="material-symbols-outlined text-2xl">logout</span>
          </button>
          {user?.avatar ? (
            <img src={`${API}${user.avatar}`} alt="You" className="w-8 h-8 rounded-full object-cover border-2 border-surface-container-high" />
          ) : (
            <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center border-2 border-surface-container-high">
              <span className="text-white text-xs font-bold">{user?.username?.[0]?.toUpperCase()}</span>
            </div>
          )}
        </div>
      </aside>

      {/* ── Main Shell ──────────────────────────────────────────────────── */}
      <main className="ml-16 flex w-full h-full overflow-hidden">
        {/* ── Conversations Panel (320px) ──────────────────────────────── */}
        <section className="w-80 h-full flex flex-col bg-surface-container-lowest">
          <div className="px-6 py-6">
            <div className="flex items-center justify-between mb-6">
              <h1 className="text-lg font-bold text-on-surface">Messages</h1>
              <button className="hover:bg-surface-container-low p-2 rounded-full transition-colors">
                <span className="material-symbols-outlined text-on-surface-variant">edit_square</span>
              </button>
            </div>
            <div className="relative">
              <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                <span className="material-symbols-outlined text-on-surface-variant text-sm">search</span>
              </div>
              <input
                className="w-full bg-surface-container-low border-none rounded-full py-2 pl-10 pr-4 text-sm focus:ring-1 focus:ring-primary outline-none transition-all"
                placeholder="Search messages..."
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar">
            <div className="px-6 py-2">
              <span className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase">
                {search ? "Results" : "Recent"}
              </span>
            </div>
            <div className="flex flex-col">
              {displayContacts.filter((c) => c._id !== user?._id).map((contact) => (
                <ConversationRow
                  key={contact._id}
                  contact={contact}
                  unread={unreadMap[contact._id] || 0}
                  lastMsg={lastMsgMap[contact._id] || null}
                  active={activeContact?._id === contact._id}
                  onClick={() => { setActiveContact(contact); setSearch(""); }}
                  isOnline={isOnline(contact._id)}
                />
              ))}
              {displayContacts.length === 0 && (
                <p className="text-center text-sm text-on-surface-variant mt-8 px-6">
                  {search ? "No users found" : "No contacts yet"}
                </p>
              )}
            </div>
          </div>
        </section>

        {/* ── Chat Panel ──────────────────────────────────────────────── */}
        {activeContact ? (
          <section className="flex-1 h-full flex flex-col bg-surface-container-low relative">
            {/* TopAppBar */}
            <header className="flex items-center justify-between px-6 py-4 bg-white/80 backdrop-blur-xl z-20 shadow-[0px_12px_32px_rgba(83,65,205,0.06)]">
              <div className="flex items-center gap-4">
                {activeContact.avatar ? (
                  <img src={`${API}${activeContact.avatar}`} alt={activeContact.username} className="w-10 h-10 rounded-full object-cover" />
                ) : (
                  <div className="w-10 h-10 rounded-full bg-primary-container flex items-center justify-center">
                    <span className="text-white font-bold">{activeContact.username[0].toUpperCase()}</span>
                  </div>
                )}
                <div>
                  <h2 className="text-sm font-bold text-on-surface">{activeContact.username}</h2>
                  <span className={`text-[10px] font-medium ${isOnline(activeContact._id) ? "text-green-500" : "text-on-surface-variant"}`}>
                    {isOnline(activeContact._id) ? "Online" : "Offline"}
                  </span>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => startCall("video")} className="hover:bg-slate-100 p-2 rounded-full transition-all" title="Video call">
                  <span className="material-symbols-outlined text-primary">videocam</span>
                </button>
                <button onClick={() => startCall("voice")} className="hover:bg-slate-100 p-2 rounded-full transition-all" title="Voice call">
                  <span className="material-symbols-outlined text-primary">call</span>
                </button>
                <button className="hover:bg-slate-100 p-2 rounded-full transition-all">
                  <span className="material-symbols-outlined text-slate-500">info</span>
                </button>
              </div>
            </header>

            {/* Thread Area */}
            <div className="flex-1 overflow-y-auto px-8 py-6 custom-scrollbar flex flex-col gap-4">
              <div className="flex justify-center my-4">
                <span className="bg-surface-container px-3 py-1 rounded-full text-[10px] font-bold text-on-surface-variant tracking-wider uppercase">
                  Today
                </span>
              </div>

              {messages.map((msg, i) => {
                const isSent = (msg.sender._id || msg.sender) === user._id;
                return isSent ? (
                  <div key={msg._id || i} className="flex items-end flex-col gap-1 ml-auto max-w-[70%]">
                    <MessageBubble msg={msg} isSent={true} />
                    <span className="text-[10px] text-on-surface-variant pr-1">
                      {formatTime(msg.createdAt)} {msg.read ? "✓✓" : "✓"}
                    </span>
                  </div>
                ) : (
                  <div key={msg._id || i} className="flex items-start gap-3 max-w-[70%] group">
                    {activeContact.avatar ? (
                      <img src={`${API}${activeContact.avatar}`} alt="" className="w-8 h-8 rounded-full self-end" />
                    ) : (
                      <div className="w-8 h-8 rounded-full bg-primary-container flex items-center justify-center self-end">
                        <span className="text-white text-xs font-bold">{activeContact.username[0].toUpperCase()}</span>
                      </div>
                    )}
                    <div className="flex flex-col gap-1">
                      <MessageBubble msg={msg} isSent={false} />
                      <span className="text-[10px] text-on-surface-variant pl-1">{formatTime(msg.createdAt)}</span>
                    </div>
                  </div>
                );
              })}

              {/* Typing indicator */}
              {partnerTyping && (
                <div className="flex items-center gap-2">
                  <div className="bg-surface-container-lowest px-4 py-3 rounded-2xl received-bubble flex gap-1">
                    {[0, 1, 2].map((i) => (
                      <span key={i} className="w-1.5 h-1.5 bg-on-surface-variant rounded-full animate-bounce"
                        style={{ animationDelay: `${i * 0.15}s` }} />
                    ))}
                  </div>
                </div>
              )}

              <div ref={bottomRef} />
            </div>

            {/* Emoji picker */}
            {showEmojiPicker && (
              <div className="absolute bottom-20 left-20 bg-white rounded-2xl shadow-xl border border-outline-variant p-3 z-30 grid grid-cols-8 gap-1">
                {emojis.map((e) => (
                  <button key={e} onClick={() => insertEmoji(e)} className="text-xl hover:bg-surface-container p-1 rounded-lg transition-colors">
                    {e}
                  </button>
                ))}
              </div>
            )}

            {/* Input Bar */}
            <footer className="p-4 bg-surface-container-lowest flex items-center gap-4 relative">
              <input
                ref={fileInputRef}
                type="file"
                className="hidden"
                onChange={handleFileSelect}
                accept="image/*,audio/*,video/*,.zip,.pdf,.doc,.docx"
              />
              <div className="flex items-center gap-1">
                <button onClick={() => fileInputRef.current?.click()} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Attach file">
                  <span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">add_circle</span>
                </button>
                <button onClick={() => fileInputRef.current?.click()} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Send image">
                  <span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">image</span>
                </button>
                <button onClick={() => setShowEmojiPicker(!showEmojiPicker)} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Emoji">
                  <span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">mood</span>
                </button>
                {/* AI Voice / Mic button */}
                <button
                  onMouseDown={startRecording}
                  onMouseUp={stopRecording}
                  onTouchStart={startRecording}
                  onTouchEnd={stopRecording}
                  title="Hold to record voice message"
                  className={`relative hover:bg-surface-container-low p-2 rounded-full transition-colors group ${recording ? "bg-red-50" : ""}`}
                >
                  <span className={`material-symbols-outlined group-hover:text-primary ${recording ? "text-red-500" : "text-on-surface-variant"}`}>
                    {recording ? "radio_button_checked" : "mic"}
                  </span>
                  {recording && <span className="absolute inset-0 rounded-full animate-ping bg-red-200 opacity-60" />}
                </button>
              </div>

              <div className="flex-1 relative">
                <input
                  className="w-full bg-surface-container-low border-none rounded-full py-3 px-6 text-sm focus:ring-1 focus:ring-primary outline-none transition-all placeholder:text-on-surface-variant/50"
                  placeholder={recording ? "Recording... release to send" : "Type a message..."}
                  type="text"
                  value={text}
                  onChange={handleTextChange}
                  onKeyDown={handleKeyDown}
                  disabled={recording}
                />
              </div>

              <button
                onClick={sendMessage}
                disabled={!text.trim()}
                className="w-11 h-11 flex items-center justify-center rounded-full bg-gradient-to-br from-primary to-primary-container text-white shadow-lg shadow-primary/20 hover:scale-105 active:scale-95 transition-all disabled:opacity-40 disabled:cursor-not-allowed"
              >
                <span className="material-symbols-outlined text-xl">send</span>
              </button>
            </footer>
          </section>
        ) : (
          /* ── Empty State ─────────────────────────────────────────────── */
          <section className="flex-1 h-full flex flex-col items-center justify-center bg-surface-container-low gap-4">
            <div className="w-20 h-20 rounded-3xl bg-primary/10 flex items-center justify-center float-anim">
              <span className="material-symbols-outlined text-5xl text-primary">chat_bubble</span>
            </div>
            <h2 className="text-lg font-bold text-on-surface">Select a conversation</h2>
            <p className="text-sm text-on-surface-variant text-center max-w-xs">
              Choose a contact from the list to start chatting, or search for someone new.
            </p>
          </section>
        )}
      </main>
    </div>
  );
}
